package pratica.na.oop.estudando.test;import pratica.na.oop.estudando.domain.Student;public class StudantTest {    public static void main(String[] args) {        Student student01 = new Student();        Student student02 = new Student();        student01.name = "Gabriel";        student01.age = 15;        student01.sex = 'm';        student01 = student02;        student02.name = "Yasmin";        student02.age = 15;        student02.sex = 'f';        String print = String.format("Estudante 1, nome é %s, idade é %d anos e sexo é %s", student01.name,                student01.age, student01.sex);        String print02 = String.format("Estudante 2, nome é %s, idade é %d anos e sexo é %s", student02.name,                student02.age, student02.sex);        System.out.println(print + "\n" + print02);    }}